	static boolean isValidPassRatio(double passRatio) {
		return Double.isFinite(passRatio) && passRatio >= 0.0d && passRatio <= 1.0d;
	}

	static boolean isFiniteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d;
	}

