	private static boolean collectOrEqualityAnchorValues(ValueExpr condition, OrEqualityAnchorCollector collector) {
		if (condition instanceof Or or) {
			return collectOrEqualityAnchorValues(or.getLeftArg(), collector)
					&& collectOrEqualityAnchorValues(or.getRightArg(), collector);
		}
		if (condition instanceof Compare compare && ((Compare) condition).getOperator() == Compare.CompareOp.EQ) {
			return collectOrEqualityAnchorValue(compare.getLeftArg(), compare.getRightArg(), collector);
		}
		if (condition instanceof SameTerm sameTerm) {
			return collectOrEqualityAnchorValue(sameTerm.getLeftArg(), sameTerm.getRightArg(), collector);
		}
		if (condition instanceof ListMemberOperator list) {
			return collectListMemberAnchorValues(list, collector);
		}
		return false;
	}

	private static boolean collectListMemberAnchorValues(ListMemberOperator list,
			OrEqualityAnchorCollector collector) {
		List<ValueExpr> arguments = list.getArguments();
		if (arguments.size() < 2) {
			return false;
		}
		ValueExpr filterArgument = arguments.getFirst();
		if (!(filterArgument instanceof Var filterVar)) {
			return false;
		}
		String bindingName = filterVar.getName();
		if (bindingName == null || filterVar.hasValue()) {
			return false;
		}
		for (int i = 1; i < arguments.size(); i++) {
			ValueExpr argument = arguments.get(i);
			if (!(argument instanceof ValueConstant)) {
				return false;
			}
			if (!collectOrEqualityAnchorValue(filterVar, ((ValueConstant) argument).getValue(), collector)) {
				return false;
			}
		}
		return true;
	}

	private static boolean collectOrEqualityAnchorValue(ValueExpr leftArg, ValueExpr rightArg,
			OrEqualityAnchorCollector collector) {
		if (leftArg instanceof Var && rightArg instanceof ValueConstant) {
			return collectOrEqualityAnchorValue((Var) leftArg, ((ValueConstant) rightArg).getValue(), collector);
		}
		if (rightArg instanceof Var && leftArg instanceof ValueConstant) {
			return collectOrEqualityAnchorValue((Var) rightArg, ((ValueConstant) leftArg).getValue(), collector);
		}
		return false;
	}

	private static boolean collectOrEqualityAnchorValue(Var filterVar, Value value,
			OrEqualityAnchorCollector collector) {
		String bindingName = filterVar.getName();
		if (bindingName == null || filterVar.hasValue() || !collector.valueFilter.test(value)) {
			return false;
		}
		if (collector.bindingName == null) {
			collector.bindingName = bindingName;
		} else if (!collector.bindingName.equals(bindingName)) {
			return false;
		}
		collector.values.add(value);
		return true;
	}

	private static String unboundName(Var var) {
		if (var == null || var.hasValue()) {
			return null;
		}
		return var.getName();
	}

	private static boolean isNamedVar(Var var, String bindingName) {
		return var != null && bindingName.equals(var.getName());
	}

	private static BindingSetAssignment smallLiteralFilterAnchor(ValueExpr leftArg, ValueExpr rightArg,
			Predicate<Value> valueFilter) {
		if (leftArg instanceof Var && rightArg instanceof ValueConstant) {
			return smallLiteralFilterAnchor((Var) leftArg, (ValueConstant) rightArg, valueFilter);
		}
		if (rightArg instanceof Var && leftArg instanceof ValueConstant) {
			return smallLiteralFilterAnchor((Var) rightArg, (ValueConstant) leftArg, valueFilter);
		}
		return null;
	}

	private static BindingSetAssignment smallLiteralFilterAnchor(Var filterVar, ValueConstant valueConstant,
			Predicate<Value> valueFilter) {
		String bindingName = filterVar.getName();
		if (bindingName == null || filterVar.hasValue()) {
			return null;
		}
		Value value = valueConstant.getValue();
		if (!valueFilter.test(value)) {
			return null;
		}
		LinkedHashSet<Value> values = new LinkedHashSet<>();
		values.add(value);
		return smallLiteralFilterAnchor(bindingName, values);
	}

	static BindingSetAssignment smallLiteralFilterAnchor(String bindingName, LinkedHashSet<Value> values) {
		if (values.isEmpty() || values.size() > SMALL_LITERAL_FILTER_ANCHOR_LIMIT) {
			return null;
		}

		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of(bindingName));
		List<BindingSet> bindingSets = new ArrayList<>(values.size());
		for (Value value : values) {
			MapBindingSet bindingSet = new MapBindingSet(1);
			bindingSet.addBinding(bindingName, value);
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	static boolean isSafeValuesAnchorValue(Value value) {
		return value != null && isValuesExpressible(value) && !isUnsafeCoreInEqualityValue(value);
	}

	private static boolean isValuesExpressible(Value value) {
		return value instanceof IRI || value instanceof Literal;
	}

	private static boolean isUnsafeCoreInEqualityValue(Value value) {
		if (!(value instanceof Literal)) {
			return false;
		}
		CoreDatatype coreDatatype = ((Literal) value).getCoreDatatype();
		if (coreDatatype.isXSDDatatype()) {
			CoreDatatype.XSD xsdDatatype = coreDatatype.asXSDDatatypeOrNull();
			return xsdDatatype.isNumericDatatype() || xsdDatatype.isCalendarDatatype()
					|| xsdDatatype.isDurationDatatype() || xsdDatatype == CoreDatatype.XSD.BOOLEAN;
		}
		return false;
	}

	private static BindingSetAssignment bindingSetAssignmentLeaf(TupleExpr tupleExpr) {
		TupleExpr current = tupleExpr;
		while (isPositionableBindingSetAssignmentWrapper(current)) {
			current = ((UnaryTupleOperator) current).getArg();
		}
		if (current instanceof BindingSetAssignment) {
			return (BindingSetAssignment) current;
		}
		return null;
	}

	private static boolean isPositionableBindingSetAssignmentWrapper(TupleExpr tupleExpr) {
		return tupleExpr instanceof Filter || tupleExpr instanceof Distinct || tupleExpr instanceof Reduced
				|| tupleExpr instanceof Slice;
	}

